+// ─── Room transition animations ─────────────────────────────────────────────
+
+/**
+ * Draws a dark archway doorway at the specified position and size.
+ * @param ctx CanvasRenderingContext2D
+ * @param x number - top-left x
+ * @param y number - top-left y
+ * @param width number - width of doorway
+ * @param height number - height of doorway
+ */
+export function drawDoorway(ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number) {
+  const archHeight = height * 0.6;
+  ctx.save();
+  ctx.fillStyle = '#222'; // dark archway base
+  // Draw rectangle base
+  ctx.fillRect(x, y + archHeight, width, height - archHeight);
+  // Draw arch - semicircle top
+  ctx.beginPath();
+  ctx.moveTo(x, y + archHeight);
+  ctx.lineTo(x, y + height);
+  ctx.lineTo(x + width, y + height);
+  ctx.lineTo(x + width, y + archHeight);
+  ctx.arc(x + width / 2, y + archHeight, width / 2, 0, Math.PI, true);
+  ctx.closePath();
+  ctx.fill();
+  // Add subtle highlight
+  const gradient = ctx.createRadialGradient(x + width / 2, y + archHeight, width / 4, x + width / 2, y + archHeight, width / 2);
+  gradient.addColorStop(0, 'rgba(255,255,255,0.1)');
+  gradient.addColorStop(1, 'rgba(0,0,0,0)');
+  ctx.fillStyle = gradient;
+  ctx.fill();
+  ctx.restore();
+}
+
+/**
+ * Draws a corridor connecting two adjacent rooms.
+ * @param ctx CanvasRenderingContext2D
+ * @param fromRoom { x:number, y:number, width:number, height:number }
+ * @param toRoom { x:number, y:number, width:number, height:number }
+ */
+export function drawCorridor(ctx: CanvasRenderingContext2D, fromRoom: {x:number,y:number,width:number,height:number}, toRoom: {x:number,y:number,width:number,height:number}) {
+  ctx.save();
+  ctx.strokeStyle = '#333';
+  ctx.lineWidth = 8;
+  ctx.lineCap = 'round';
+  // Compute center points of rooms
+  const fromCenterX = fromRoom.x + fromRoom.width / 2;
+  const fromCenterY = fromRoom.y + fromRoom.height / 2;
+  const toCenterX = toRoom.x + toRoom.width / 2;
+  const toCenterY = toRoom.y + toRoom.height / 2;
+  // Draw corridor line
+  ctx.beginPath();
+  ctx.moveTo(fromCenterX, fromCenterY);
+  ctx.lineTo(toCenterX, toCenterY);
+  ctx.stroke();
+  ctx.restore();
+}
+
+/**
+ * Draws a room with a subtle fade-in effect over 5 frames.
+ * @param ctx CanvasRenderingContext2D
+ * @param drawRoomFn () => void - function that draws the room normally
+ * @param frame number - current frame number (0 to 4)
+ */
+export function drawRoomWithFadeIn(ctx: CanvasRenderingContext2D, drawRoomFn: () => void, frame: number) {
+  ctx.save();
+  const alpha = Math.min(1, (frame + 1) / 5);
+  ctx.globalAlpha = alpha;
+  drawRoomFn();
+  ctx.restore();
+}
